DELETE FROM bpm_node_instance
WHERE T_DAY = #{tDay}
  AND SCENE_ID = #{sceneId}

      AND node_code LIKE CONCAT(#{nodeCodePrefix}, '%')


      AND 1 = 1

mapper.update:
UPDATE bpm_node_instance t1
SET status = 'READ_ONLY'
WHERE t1.T_DAY = #{tDay}
  AND t1.SCENE_ID = #{sceneId}
  AND IFNULL(t1.ORG_BUSI_BRANCH, '@') = '@'
  AND t1.NODE_TYPE_ID IN

      #{id}


      AND t1.node_code LIKE CONCAT(#{nodeCodePrefix}, '%')

  AND t1.id NOT IN (
      SELECT node_instance_id FROM bpm_node_instance_office
      WHERE delete_flag = '0'
  )

UPDATE bpm_node_instance t1
SET reference_node_id = (
    SELECT t_s.id FROM bpm_node_instance t_s
    WHERE t_s.title = t1.title
      AND CONCAT(t1.description, '+') = CONCAT(t_s.description, '+')
      AND t_s.ORG_BRANCH = 'ALL'
      AND t_s.T_DAY = #{tDay}
      AND t_s.SCENE_ID = #{sceneId}
    LIMIT 1
)
WHERE t1.T_DAY = #{tDay}
  AND t1.SCENE_ID = #{sceneId}
  AND t1.status = 'READ_ONLY'
  AND t1.ORG_CEN_BRANCH = 'ALL'
  AND t1.ORG_BRANCH != 'ALL'
  AND t1.NODE_TYPE_ID IN (
      SELECT id FROM bpm_node_type WHERE type_key = 'READONLY'
  )

      AND t1.node_code LIKE CONCAT(#{nodeCodePrefix}, '%')

